import { useAutoSaveSettings } from '@/shared/settings/hooks/useAutoSaveSettings';
import type { Json } from '@/integrations/supabase/jsonTypes';
import { toJson } from '@/shared/lib/supabaseTypeHelpers';
import { fetchGenerationRecordById } from '@/integrations/supabase/repositories/generationRepository';
import { updateGenerationParams } from '@/integrations/supabase/repositories/generationMutationsRepository';

// Import canonical types from single source of truth
import {
  type EditMode,
  type LoraMode,
  type QwenEditModel,
  type EditAdvancedSettings,
  type VideoEnhanceSettings,
  type GenerationEditSettings,
  type EditSettingsSetterMethods,
  type SyncedEditSettings,
  DEFAULT_EDIT_SETTINGS
} from '../model/editSettingsTypes';

// Re-export types for backwards compatibility
export type { EditMode, QwenEditModel, EditAdvancedSettings, VideoEnhanceSettings };
// Defaults are internal-only - import from editSettingsTypes directly if needed

/**
 * Result type for convertToHiresFixApiParams - includes num_inference_steps for single-pass mode.
 */
interface EditApiParams {
  num_inference_steps?: number;
  hires_scale?: number;
  hires_steps?: number;
  hires_denoise?: number;
  lightning_lora_strength_phase_1?: number;
  lightning_lora_strength_phase_2?: number;
}

type JsonObject = { [key: string]: Json | undefined };
type AutoSaveGenerationEditSettings = GenerationEditSettings & Record<string, unknown>;

/**
 * Converts EditAdvancedSettings to API params for task creation.
 * Returns hires params if two-pass is enabled, or just num_inference_steps if disabled.
 */
export function convertToHiresFixApiParams(settings: EditAdvancedSettings | undefined): EditApiParams | undefined {
  if (!settings) {
    return undefined;
  }

  if (!settings.enabled) {
    // Two-pass disabled: just return num_inference_steps for single-pass generation
    return {
      num_inference_steps: settings.num_inference_steps,
    };
  }

  // Two-pass enabled: return hires params (base_steps is used as num_inference_steps for phase 1)
  return {
    num_inference_steps: settings.base_steps,
    hires_scale: settings.hires_scale,
    hires_steps: settings.hires_steps,
    hires_denoise: settings.hires_denoise,
    lightning_lora_strength_phase_1: settings.lightning_lora_strength_phase_1,
    lightning_lora_strength_phase_2: settings.lightning_lora_strength_phase_2,
  };
}

interface UseGenerationEditSettingsReturn extends EditSettingsSetterMethods {
  // Current settings
  settings: GenerationEditSettings;

  // Bulk update
  updateSettings: (updates: Partial<GenerationEditSettings>) => void;
  flushTextFields: () => Promise<void>;

  // State
  isLoading: boolean;
  hasPersistedSettings: boolean;

  // For initialization from "last used"
  initializeFromLastUsed: (lastUsed: SyncedEditSettings & { editMode: EditMode }) => void;
}

interface UseGenerationEditSettingsProps {
  generationId: string | null;
  enabled?: boolean;
  bootstrapSettings?: (SyncedEditSettings & { editMode: EditMode }) | null;
}

/**
 * Load settings from generations.params.ui.editSettings
 */
async function loadGenerationSettings(generationId: string): Promise<AutoSaveGenerationEditSettings | null> {
  const generation = await fetchGenerationRecordById(generationId);
  if (!generation) {
    return null;
  }

  const savedSettings = (generation.params as Record<string, unknown> | null | undefined)?.ui as Record<string, unknown> | undefined;
  const editSettings = savedSettings?.editSettings as Partial<GenerationEditSettings> | undefined;

  if (editSettings) {
    return {
      ...DEFAULT_EDIT_SETTINGS,
      ...editSettings,
    };
  }

  return null;
}

/**
 * Save settings to generations.params.ui.editSettings
 */
async function saveGenerationSettings(generationId: string, settings: AutoSaveGenerationEditSettings): Promise<void> {
  // Fetch current params to merge
  const current = await fetchGenerationRecordById(generationId);

  if (!current) {
    // Generation was deleted, skip save
    return;
  }

  // Merge with existing params
  const currentParams = ((current?.params as JsonObject | null) ?? {});
  const currentUi = ((currentParams.ui as JsonObject | undefined) ?? {});
  const updatedParams: JsonObject = {
    ...currentParams,
    ui: {
      ...currentUi,
      editSettings: toJson(settings),
      // Also save editMode at top level for backwards compatibility
      editMode: settings.editMode,
    }
  };

  await updateGenerationParams({
    id: generationId,
    generationParams: toJson(updatedParams),
  });
}

/**
 * Hook for managing per-generation edit settings persistence
 *
 * Uses useAutoSaveSettings (customLoadSave mode) for the core persistence logic:
 * - Status machine (idle ‚Üí loading ‚Üí ready ‚Üí saving)
 * - Debounced auto-save
 * - Pending refs protection
 * - Flush on unmount/entity change
 *
 * Saves to: generations.params.ui.editSettings
 */
export function useGenerationEditSettings({
  generationId,
  enabled = true,
  bootstrapSettings = null,
}: UseGenerationEditSettingsProps): UseGenerationEditSettingsReturn {
  const queryClient = useQueryClient();
  const bootstrapData = bootstrapSettings
    ? {
        ...DEFAULT_EDIT_SETTINGS,
        ...bootstrapSettings,
        prompt: '',
        img2imgPrompt: '',
        img2imgPromptHasBeenSet: false,
      }
    : null;

  // Use the base persistent state hook (customLoadSave mode)
  const {
    settings,
    status,
    hasPersistedData: hasPersistedSettings,
    updateField,
    updateFields,
    updateTextField,
    updateTextFields,
    save,
    initializeFrom,
  } = useAutoSaveSettings<AutoSaveGenerationEditSettings>({
    defaults: DEFAULT_EDIT_SETTINGS as AutoSaveGenerationEditSettings,
    debounceMs: 500,
    enabled,
    bootstrapData: bootstrapData as AutoSaveGenerationEditSettings | null,
    debugTag: '[useGenerationEditSettings]',
    customLoadSave: {
      entityId: generationId,
      domainKey: 'generation-edit-settings',
      load: loadGenerationSettings,
      save: saveGenerationSettings,
      onFlush: (entityId) => {
        // Invalidate generation queries after flush
        queryClient.invalidateQueries({
          queryKey: generationQueryKeys.detail(entityId)
        });
      },
    },
    onSaveSuccess: () => {
      if (generationId) {
        queryClient.invalidateQueries({
          queryKey: generationQueryKeys.detail(generationId)
        });
      }
    },
  });
  const advancedSettingsRef = useRef(settings.advancedSettings);
  advancedSettingsRef.current = settings.advancedSettings;
  const enhanceSettingsRef = useRef(settings.enhanceSettings);
  enhanceSettingsRef.current = settings.enhanceSettings;

  // Individual setters that delegate to updateField
  const setEditMode = useCallback((mode: EditMode) => {
    updateField('editMode', mode);
  }, [updateField]);

  const setLoraMode = useCallback((mode: LoraMode) => {
    updateField('loraMode', mode);
  }, [updateField]);

  const setCustomLoraUrl = useCallback((url: string) => {
    updateTextField('customLoraUrl', url);
  }, [updateTextField]);

  const setNumGenerations = useCallback((num: number) => {
    updateField('numGenerations', num);
  }, [updateField]);

  const setPrompt = useCallback((prompt: string) => {
    updateTextField('prompt', prompt);
  }, [updateTextField]);

  const setQwenEditModel = useCallback((model: QwenEditModel) => {
    updateField('qwenEditModel', model);
  }, [updateField]);

  const setImg2imgPrompt = useCallback((prompt: string) => {
    updateTextFields({ img2imgPrompt: prompt, img2imgPromptHasBeenSet: true });
  }, [updateTextFields]);

  const setImg2imgStrength = useCallback((strength: number) => {
    updateField('img2imgStrength', strength);
  }, [updateField]);

  const setImg2imgEnablePromptExpansion = useCallback((enabled: boolean) => {
    updateField('img2imgEnablePromptExpansion', enabled);
  }, [updateField]);

  // Advanced settings setter (merges with existing)
  const setAdvancedSettings = useCallback((updates: Partial<EditAdvancedSettings>) => {
    updateFields({
      advancedSettings: { ...advancedSettingsRef.current, ...updates },
    });
  }, [updateFields]);

  // Video enhance settings setter (merges with existing)
  const setEnhanceSettings = useCallback((updates: Partial<VideoEnhanceSettings>) => {
    updateFields({
      enhanceSettings: { ...enhanceSettingsRef.current, ...updates },

      enhanceSettings: { ...enhanceSettingsRef.current, ...updates },
    });
  }, [updateFields]);

  const setCreateAsGeneration = useCallback((value: boolean) => {
    updateField('createAsGeneration', value);
  }, [updateField]);

  // Bulk update
  const updateSettings = useCallback((updates: Partial<GenerationEditSettings>) => {
    updateFields(updates);
  }, [updateFields]);

  const flushTextFields = useCallback(async () => {
    await save();
  }, [save]);

  // Initialize from "last used" - wraps initializeFrom with prompt exclusion
  const initializeFromLastUsed = useCallback((lastUsed: SyncedEditSettings & { editMode: EditMode }) => {
    // Apply last used but never inherit prompts
    initializeFrom({
      ...lastUsed,
      prompt: '',
      img2imgPrompt: '',
      img2imgPromptHasBeenSet: false,
    });
  }, [initializeFrom]);

  return {
    settings,
    setEditMode,
    setLoraMode,
    setCustomLoraUrl,
    setNumGenerations,
    setPrompt,
    setQwenEditModel,
    setImg2imgPrompt,
    setImg2imgStrength,
    setImg2imgEnablePromptExpansion,
    setAdvancedSettings,
    setEnhanceSettings,
    setCreateAsGeneration,
    updateSettings,
    flushTextFields,
    isLoading: status === 'loading' || status === 'idle',
    hasPersistedSettings,
    initializeFromLastUsed,
  };
}

import { useMemo, useCallback } from 'react';
import { useGenerationEditSettings } from '../useGenerationEditSettings';
import { useLastUsedEditSettings } from '../useLastUsedEditSettings';

// Import canonical types from single source of truth
import {
  type EditMode,
  type LoraMode,
  type QwenEditModel,
  type EditAdvancedSettings,
  type VideoEnhanceSettings,
  type GenerationEditSettings,
  type EditSettingsSetterMethods,
  type LastUsedEditSettings,
  type VideoEditSubMode,
  type PanelMode,
  DEFAULT_EDIT_SETTINGS,
  DEFAULT_ADVANCED_SETTINGS,
  DEFAULT_ENHANCE_SETTINGS,
} from '../../model/editSettingsTypes';
import { resolveEditModeLoras } from '@/domains/lora/lib/loraUtils';

interface UseEditSettingsPersistenceProps {
  generationId: string | null;
  projectId: string | null;
  enabled?: boolean;
}

interface UseEditSettingsPersistenceReturn extends EditSettingsSetterMethods {
  // Current settings values
  editMode: EditMode;
  loraMode: LoraMode;
  customLoraUrl: string;
  numGenerations: number;
  prompt: string;
  // Img2Img values
  img2imgPrompt: string;
  img2imgPromptHasBeenSet: boolean;
  img2imgStrength: number;
  img2imgEnablePromptExpansion: boolean;
  // Advanced settings for two-pass generation
  advancedSettings: EditAdvancedSettings;
  // Video enhance settings (interpolation/upscaling)
  enhanceSettings: VideoEnhanceSettings;
  // Model selection for cloud mode
  qwenEditModel: QwenEditModel;
  // Generation options
  createAsGeneration: boolean;

  // Video/Panel mode settings (persisted to "last used" only)
  videoEditSubMode: VideoEditSubMode;
  panelMode: PanelMode;
  setVideoEditSubMode: (mode: VideoEditSubMode) => void;
  setPanelMode: (mode: PanelMode) => void;

  // Computed LoRAs for task creation
  editModeLoras: Array<{ url: string; strength: number }> | undefined;
  flushTextFields: () => Promise<void>;

  // State
  isLoading: boolean;
  isReady: boolean; // True when initialization is complete
  hasPersistedSettings: boolean;
}

/**
 * Unified edit settings persistence hook
 *
 * Coordinates:
 * 1. Per-generation settings (generations.params.ui.editSettings)
 * 2. "Last used" settings (useToolSettings + localStorage)
 *
 * Loading behavior:
 * - If generation has persisted settings ‚Üí use those (including prompt)
 * - If no persisted settings ‚Üí use "last used" (prompt = '')
 *
 * Saving behavior:
 * - All changes save to generation
 * - Non-prompt changes also update "last used"
 */
export function useEditSettingsPersistence({
  generationId,
  projectId,
  enabled = true,
}: UseEditSettingsPersistenceProps): UseEditSettingsPersistenceReturn {
  // "Last used" settings
  const lastUsedSettings = useLastUsedEditSettings({
    projectId,
    enabled,
  });

  // Per-generation settings
  const generationSettings = useGenerationEditSettings({
    generationId,
    enabled,
    bootstrapSettings: lastUsedSettings.lastUsed,
  });

  // Extract stable references
  const { lastUsed } = lastUsedSettings;

  // Compute effective values
  // editMode is ALWAYS from lastUsed (user-level, not per-generation) so it stays consistent across images/videos
  // Other settings like prompt, loraMode are per-generation
  const effectiveSettings = useMemo(() => {
    if (generationSettings.isLoading) {
      // Still loading, use defaults but editMode from lastUsed
      return {
        ...DEFAULT_EDIT_SETTINGS,
        editMode: lastUsedSettings.lastUsed.editMode,
      };
    }

    if (generationSettings.hasPersistedSettings) {
      // Has persisted settings, use them BUT override editMode with lastUsed (user-level)
      return {
        ...generationSettings.settings,
        editMode: lastUsedSettings.lastUsed.editMode,
      };
    }

    // No persisted settings yet: use last-used values for synced fields and the live
    // generation-scoped values for prompt/model-only fields.
    return {
      ...DEFAULT_EDIT_SETTINGS,
      ...lastUsedSettings.lastUsed,
      ...generationSettings.settings,
      editMode: lastUsedSettings.lastUsed.editMode,
    };
  }, [
    generationSettings.isLoading,
    generationSettings.hasPersistedSettings,
    generationSettings.settings,
    lastUsedSettings.lastUsed,
  ]);

  // Extract stable function references to avoid recreating callbacks on every render
  // (the parent objects are recreated each render, but these functions are stable)
  const { updateLastUsed } = lastUsedSettings;
  const {
    setEditMode: genSetEditMode,
    setLoraMode: genSetLoraMode,
    setCustomLoraUrl: genSetCustomLoraUrl,
    setNumGenerations: genSetNumGenerations,
    setPrompt: genSetPrompt,
    setQwenEditModel: genSetQwenEditModel,
    setImg2imgPrompt: genSetImg2imgPrompt,
    setImg2imgStrength: genSetImg2imgStrength,
    setImg2imgEnablePromptExpansion: genSetImg2imgEnablePromptExpansion,
    setAdvancedSettings: genSetAdvancedSettings,
    setEnhanceSettings: genSetEnhanceSettings,
    setCreateAsGeneration: genSetCreateAsGeneration,
    flushTextFields: flushGenerationTextFields,
  } = generationSettings;

  // Wrapper setters that also update "last used" (except prompt)
  // editMode writes to both generation persistence and user-level last used state.
  const setEditMode = useCallback((mode: EditMode) => {
    genSetEditMode(mode);
    updateLastUsed({ editMode: mode });
  }, [genSetEditMode, updateLastUsed]);

  const setLoraMode = useCallback((mode: LoraMode) => {
    genSetLoraMode(mode);
    updateLastUsed({ loraMode: mode });
  }, [genSetLoraMode, updateLastUsed]);

  const setCustomLoraUrl = useCallback((url: string) => {
    genSetCustomLoraUrl(url);
  }, [genSetCustomLoraUrl]);

  const setNumGenerations = useCallback((num: number) => {
    genSetNumGenerations(num);
    updateLastUsed({ numGenerations: num });
  }, [genSetNumGenerations, updateLastUsed]);

  // Prompt only saves to generation (never to "last used")
  const setPrompt = useCallback((prompt: string) => {
    genSetPrompt(prompt);
  }, [genSetPrompt]);

  // Model selection (saves to generation, cloud mode only)
  const setQwenEditModel = useCallback((model: QwenEditModel) => {
    genSetQwenEditModel(model);
  }, [genSetQwenEditModel]);

  // Img2Img prompt only saves to generation (never to "last used")
  const setImg2imgPrompt = useCallback((prompt: string) => {
    genSetImg2imgPrompt(prompt);
  }, [genSetImg2imgPrompt]);

  const flushTextFields = useCallback(async () => {
    await flushGenerationTextFields();
    updateLastUsed({ customLoraUrl: generationSettings.settings.customLoraUrl });
  }, [flushGenerationTextFields, updateLastUsed, generationSettings.settings.customLoraUrl]);

  // Img2Img setters (save to both generation and "last used")
  const setImg2imgStrength = useCallback((strength: number) => {
    genSetImg2imgStrength(strength);
    updateLastUsed({ img2imgStrength: strength });
  }, [genSetImg2imgStrength, updateLastUsed]);

  const setImg2imgEnablePromptExpansion = useCallback((enabled: boolean) => {
    genSetImg2imgEnablePromptExpansion(enabled);
    updateLastUsed({ img2imgEnablePromptExpansion: enabled });
  }, [genSetImg2imgEnablePromptExpansion, updateLastUsed]);

  // Advanced settings setter (merges with existing, saves to both generation and "last used")
  const setAdvancedSettings = useCallback((updates: Partial<EditAdvancedSettings>) => {
    genSetAdvancedSettings(updates);
    // Merge updates with current advancedSettings for lastUsed
    const currentAdvanced = effectiveSettings.advancedSettings ?? DEFAULT_ADVANCED_SETTINGS;
    updateLastUsed({ advancedSettings: { ...currentAdvanced, ...updates } });
  }, [genSetAdvancedSettings, updateLastUsed, effectiveSettings.advancedSettings]);

  // Video enhance settings setter (per-generation only, not "last used")
  const setEnhanceSettings = useCallback((updates: Partial<VideoEnhanceSettings>) => {
    genSetEnhanceSettings(updates);
  }, [genSetEnhanceSettings]);

  // Generation options setter (saves to both generation and "last used")
  const setCreateAsGeneration = useCallback((value: boolean) => {
    genSetCreateAsGeneration(value);
    updateLastUsed({ createAsGeneration: value });
  }, [genSetCreateAsGeneration, updateLastUsed]);

  // Video/Panel mode setters (only save to "last used", not per-generation)
  const setVideoEditSubMode = useCallback((mode: VideoEditSubMode) => {
    updateLastUsed({ videoEditSubMode: mode });
  }, [updateLastUsed]);

  const setPanelMode = useCallback((mode: PanelMode) => {
    updateLastUsed({ panelMode: mode });
  }, [updateLastUsed]);

  // Computed LoRAs based on mode (replaces useEditModeLoras logic)
  const loraMode = effectiveSettings.loraMode;
  const customLoraUrl = effectiveSettings.customLoraUrl;
  const editModeLoras = useMemo(
    () => resolveEditModeLoras(loraMode, customLoraUrl),
    [loraMode, customLoraUrl],
  );

  return useMemo(
    () => ({
      // Current values (using effective settings to avoid race condition)
      editMode: effectiveSettings.editMode,
      loraMode: effectiveSettings.loraMode,
      customLoraUrl: effectiveSettings.customLoraUrl,
      numGenerations: effectiveSettings.numGenerations,
      prompt: effectiveSettings.prompt,
      // Img2Img values
      img2imgPrompt: effectiveSettings.img2imgPrompt,
      img2imgPromptHasBeenSet: effectiveSettings.img2imgPromptHasBeenSet,
      img2imgStrength: effectiveSettings.img2imgStrength,
      img2imgEnablePromptExpansion: effectiveSettings.img2imgEnablePromptExpansion,
      // Advanced settings (hires fix config)
      advancedSettings: effectiveSettings.advancedSettings ?? DEFAULT_ADVANCED_SETTINGS,
      // Video enhance settings (interpolation/upscaling)
      enhanceSettings: effectiveSettings.enhanceSettings ?? DEFAULT_ENHANCE_SETTINGS,

import { useCallback, useEffect, useMemo } from 'react';
import { useToolSettings } from '@/shared/hooks/settings/useToolSettings';
import { SETTINGS_IDS } from '@/shared/lib/settingsIds';
import { deepEqual } from '@/shared/lib/utils/deepEqual';
import { createEntityStore, type EntityStoreApi } from '@/shared/state/createEntityStore';

import {
  type LastUsedEditSettings,
  type VideoEditSubMode,
  type PanelMode,
  DEFAULT_LAST_USED,
} from '../model/editSettingsTypes';

export type { LastUsedEditSettings, VideoEditSubMode, PanelMode };

const STORAGE_KEY_PROJECT = (projectId: string) => `lightbox-edit-last-used-${projectId}`;
const STORAGE_KEY_GLOBAL = 'lightbox-edit-last-used-global';
const DISABLED_ENTITY_ID = '__lightbox-last-used-disabled__';
const LAST_USED_DOMAIN_KEY = 'lightbox-last-used-edit-settings';

interface UseLastUsedEditSettingsReturn {
  lastUsed: LastUsedEditSettings;
  updateLastUsed: (settings: Partial<LastUsedEditSettings>) => void;
  isLoading: boolean;
}

interface UseLastUsedEditSettingsProps {
  projectId: string | null;
  enabled?: boolean;
}

interface LastUsedStoreRuntime {
  updateDbSettingsRef: {
    current: ((scope: 'user' | 'project' | 'shot', settings: Partial<LastUsedEditSettings>) => Promise<void>) | null;
  };
}

function hasSettingsChanged(prev: LastUsedEditSettings, next: LastUsedEditSettings): boolean {
  return !deepEqual(prev, next);
}

function readLocalStorageSettings(projectId: string | null): LastUsedEditSettings {
  if (!projectId) {
    return DEFAULT_LAST_USED;
  }

  try {
    const projectStored = localStorage.getItem(STORAGE_KEY_PROJECT(projectId));
    if (projectStored) {
      return { ...DEFAULT_LAST_USED, ...JSON.parse(projectStored) };
    }

    const globalStored = localStorage.getItem(STORAGE_KEY_GLOBAL);
    if (globalStored) {
      return { ...DEFAULT_LAST_USED, ...JSON.parse(globalStored) };
    }
  } catch {
    // Ignore storage corruption and fall back to defaults.
  }

  return DEFAULT_LAST_USED;
}

function writeLocalStorageSettings(projectId: string, settings: LastUsedEditSettings): void {
  try {
    localStorage.setItem(STORAGE_KEY_PROJECT(projectId), JSON.stringify(settings));
    localStorage.setItem(STORAGE_KEY_GLOBAL, JSON.stringify(settings));
  } catch {
    // Ignore storage write failures; DB sync remains best effort.
  }
}

let lastUsedStoreCache:
  | {
      store: EntityStoreApi<LastUsedEditSettings>;
      runtime: LastUsedStoreRuntime;
    }
  | null = null;

function getLastUsedStore(): {
  store: EntityStoreApi<LastUsedEditSettings>;
  runtime: LastUsedStoreRuntime;
} {
  if (lastUsedStoreCache) {
    return lastUsedStoreCache;
  }

  const runtime: LastUsedStoreRuntime = {
    updateDbSettingsRef: { current: null },
  };

  const store = createEntityStore<LastUsedEditSettings>({
    toolId: LAST_USED_DOMAIN_KEY,
    defaults: DEFAULT_LAST_USED,
    load: async (entityId) => ({
      db: null,
      lastUsed: entityId === DISABLED_ENTITY_ID ? null : readLocalStorageSettings(entityId),
    }),
    save: async (entityId, data) => {
      if (entityId === DISABLED_ENTITY_ID) {
        return;
      }

      writeLocalStorageSettings(entityId, data);
      try {
        await runtime.updateDbSettingsRef.current?.('user', data);
      } catch {
        // Preserve local writes even if cross-device sync fails.
      }
    },
  });

  lastUsedStoreCache = { store, runtime };
  return lastUsedStoreCache;
}

export function useLastUsedEditSettings({
  projectId,
  enabled = true,
}: UseLastUsedEditSettingsProps): UseLastUsedEditSettingsReturn {
  const entityId = enabled && projectId ? projectId : null;
  const activeEntityId = entityId ?? DISABLED_ENTITY_ID;
  const { store, runtime } = useMemo(() => getLastUsedStore(), []);

  const {
    settings: dbSettings,
    isLoading: isDbLoading,
    update: updateDbSettings,
  } = useToolSettings<LastUsedEditSettings>(SETTINGS_IDS.LIGHTBOX_EDIT, {
    projectId: projectId || undefined,
    enabled: enabled && !!projectId,
  });

  runtime.updateDbSettingsRef.current = updateDbSettings;

  const entity = store.useEntity(activeEntityId);
  const storeState = store.getState();
  const bootstrapEntity = storeState.bootstrapEntity;
  const updateStoredFields = storeState.updateFields;
  const saveStoredEntityImmediately = storeState.saveImmediate;
  const reloadStoredEntity = storeState.reloadEntity;
  const fallbackLastUsed = useMemo(
    () => (entityId ? readLocalStorageSettings(entityId) : DEFAULT_LAST_USED),
    [entityId]
  );

  useEffect(() => {
    if (!entityId) {
      return;
    }

    void reloadStoredEntity(entityId).catch(() => {});
  }, [entityId, reloadStoredEntity]);

  useEffect(() => {
    if (!entityId) {
      return;
    }

    const localSettings = readLocalStorageSettings(entityId);
    const dbSnapshot = dbSettings ? { ...localSettings, ...dbSettings } : null;
    const currentEntity = store.getState().entities[entityId];
    const nextSeed = dbSnapshot ?? localSettings;

    if (
      currentEntity
      && currentEntity.loaded
      && currentEntity.hasPersistedData === (dbSnapshot !== null)
      && deepEqual(currentEntity.cleanSnapshot, nextSeed)
    ) {
      return;
    }

    bootstrapEntity({
      entityId,
      db: dbSnapshot,
      lastUsed: localSettings,
    });
  }, [bootstrapEntity, dbSettings, entityId, store]);

  const updateLastUsed = useCallback((updates: Partial<LastUsedEditSettings>) => {
    if (!entityId) {
      return;
    }

    const currentSettings = store.getState().entities[entityId]?.settings ?? readLocalStorageSettings(entityId);
    const nextSettings = { ...currentSettings, ...updates };
    if (!hasSettingsChanged(currentSettings, nextSettings)) {
      return;
    }

    updateStoredFields(entityId, updates);
    void saveStoredEntityImmediately(entityId).catch(() => {});
  }, [entityId, saveStoredEntityImmediately, store, updateStoredFields]);

  const currentEntity = entityId ? store.getState().entities[entityId] : undefined;
  const lastUsed = entityId
    ? (currentEntity?.loaded ? entity.settings : fallbackLastUsed)
    : DEFAULT_LAST_USED;

  return useMemo(() => ({
    lastUsed,
    updateLastUsed,
    isLoading: !!entityId && isDbLoading,
  }), [entityId, isDbLoading, lastUsed, updateLastUsed]);
}

