// ---------------------------------------------------------------------------
// Preview composition ‚Äî colored rectangle wrapped by the effect component
// ---------------------------------------------------------------------------

const PREVIEW_FPS = 30;
const PREVIEW_SIZE = 320;

interface PreviewParams {
  durationSeconds: number;
  effectSeconds: number;
  intensity: number;
}

const DEFAULT_PREVIEW_PARAMS: PreviewParams = {
  durationSeconds: 3,
  effectSeconds: 0.7,
  intensity: 0.5,
};

function PreviewRect({ assetSrc }: { assetSrc?: string | null }) {
  if (assetSrc) {
    const isVideo = /\.(mp4|mov|webm|m4v)(\?|$)/i.test(assetSrc);
    return (
      <AbsoluteFill>
        {isVideo ? (
          <video
            src={assetSrc}
            muted
            loop
            autoPlay
            playsInline
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        ) : (
          <img
            src={assetSrc}
            alt=""
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        )}
      </AbsoluteFill>
    );
  }

  return (
    <AbsoluteFill
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #6366f1 0%, #8b5cf6 50%, #a78bfa 100%)',
      }}
    >
      <div
        style={{
          width: '60%',
          height: '60%',
          borderRadius: 16,
          background: 'rgba(255,255,255,0.15)',
          backdropFilter: 'blur(8px)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: '#fff',
          fontSize: 24,
          fontWeight: 600,
          letterSpacing: 1,
        }}
      >
        Effect Preview
      </div>
    </AbsoluteFill>
  );
}

function makePreviewComposition(
  EffectComponent: FC<EffectComponentProps> | null,
  category: EffectCategory,
  params: PreviewParams,
  effectParams: Record<string, unknown>,
  fps: number,
  schema?: ParameterSchema,
  assetSrc?: string | null,
) {
  const durationInFrames = Math.max(1, Math.round(params.durationSeconds * fps));
  const effectFrames = category === 'continuous'
    ? durationInFrames
    : Math.max(1, Math.round(params.effectSeconds * fps));

  const wrapPreviewEffect = (content: ReactNode) => {
    const fallback = <PreviewRect assetSrc={assetSrc} />;
    if (!EffectComponent) {
      return fallback;
    }

    return (
      <EffectErrorBoundary effectName="preview" fallback={fallback}>
        <EffectComponent
          durationInFrames={durationInFrames}
          effectFrames={effectFrames}
          intensity={params.intensity}
          params={validateAndCoerceParams(effectParams, schema)}
        >
          {content}
        </EffectComponent>
      </EffectErrorBoundary>
    );
  };

  return function EffectPreviewComposition() {
    return wrapPreviewEffect(
      <AbsoluteFill style={{ overflow: 'hidden' }}>
        <PreviewRect assetSrc={assetSrc} />
      </AbsoluteFill>,
    );
  };
}

