import { useEffect, useRef, useState, type ReactNode } from 'react';
import { Paintbrush, Pencil, Type, Move, Wand2, ArrowUp } from 'lucide-react';
import React from 'react';
import type {
  EditModePanelCoreState,
  EditModePanelImageEditState,
  EditModePanelVariantsState,
} from '../components/types';

interface UseEditModePanelStateParams {
  variant: 'desktop' | 'mobile';
  currentMediaId: string;

  isCloudMode?: boolean;
  handleUpscale?: () => Promise<void>;

  coreState: EditModePanelCoreState;
  imageEditState: EditModePanelImageEditState;
  variantsState: EditModePanelVariantsState;
}

export interface ModeSelectorItem {
  id: string;
  label: string;
  icon: ReactNode;
  onClick: () => void;
}

export function useEditModePanelState({
  variant,
  currentMediaId,
  isCloudMode,
  handleUpscale,
  coreState,
  imageEditState,
  variantsState,
}: UseEditModePanelStateParams) {
  const isMobile = variant === 'mobile';
  const { onClose } = coreState;

  const {
    editMode,
    setEditMode,
    setIsInpaintMode,
    brushStrokes,
    handleExitMagicEditMode,
    hasTransformChanges,
  } = imageEditState;

  const {
    inpaintPrompt,
    setInpaintPrompt,
    inpaintNumGenerations,
    setInpaintNumGenerations,
    flushTextFields,
    loraMode,
    setLoraMode,
    customLoraUrl,
    setCustomLoraUrl,
    createAsGeneration,
    setCreateAsGeneration,
    img2imgPrompt,
    setImg2imgPrompt,
    img2imgStrength,
    setImg2imgStrength,
    setEnablePromptExpansion,
    qwenEditModel,
    setQwenEditModel,
  } = imageEditState;

  const {
    isGeneratingReposition,
    repositionGenerateSuccess,
    isSavingAsVariant,
    saveAsVariantSuccess,
    isGeneratingInpaint,
    inpaintGenerateSuccess,
    isCreatingMagicEditTasks,
    magicEditTasksCreated,
    isGeneratingImg2Img,
    img2imgGenerateSuccess,
  } = imageEditState;

  const {
    variants,
    activeVariant,
    handleVariantSelect: onVariantSelect,
    handleMakePrimary: onMakePrimary,
    isLoadingVariants = false,
    handlePromoteToGeneration: onPromoteToGeneration,
    isPromoting = false,
    handleDeleteVariant: onDeleteVariant,
    onLoadVariantSettings,
    pendingTaskCount = 0,
    unviewedVariantCount = 0,
    onMarkAllViewed,
    onLoadVariantImages,
    currentSegmentImages,
  } = variantsState;

  const activeVariantId = activeVariant?.id || null;
  const prevEditModeRef = useRef(editMode);
  const [hasUserEditedPrompt, setHasUserEditedPrompt] = useState(false);
  const prevMediaIdRef = useRef(currentMediaId);
  useEffect(() => {
    if (currentMediaId !== prevMediaIdRef.current) {
      setHasUserEditedPrompt(false);
      prevMediaIdRef.current = currentMediaId;
    }
  }, [currentMediaId]);

  useEffect(() => {
    const prevMode = prevEditModeRef.current;
    if (prevMode !== editMode && (editMode === 'inpaint' || editMode === 'annotate')) {
      setLoraMode('none');
    }
    prevEditModeRef.current = editMode;
  }, [editMode, setLoraMode]);

  useEffect(() => {
    if (!isCloudMode && qwenEditModel?.startsWith('flux-klein-')) {
      setQwenEditModel('qwen-edit');
    }
  }, [isCloudMode, qwenEditModel, setQwenEditModel]);

  const handleClearLora = (e: React.MouseEvent) => {
    e.stopPropagation();
    setLoraMode('none');
  };

  const modeSelectorItems: ModeSelectorItem[] = [
    {
      id: 'text',
      label: 'Text',
      icon: React.createElement(Type),
      onClick: () => { setIsInpaintMode(true); setEditMode('text'); },
    },
    {
      id: 'inpaint',
      label: 'Paint',
      icon: React.createElement(Paintbrush),
      onClick: () => { setIsInpaintMode(true); setEditMode('inpaint'); },
    },
    {
      id: 'annotate',
      label: 'Annotate',
      icon: React.createElement(Pencil),
      onClick: () => { setIsInpaintMode(true); setEditMode('annotate'); },
    },
    {
      id: 'reposition',
      label: 'Move',
      icon: React.createElement(Move),
      onClick: () => { setIsInpaintMode(true); setEditMode('reposition'); },
    },
    {
      id: 'img2img',
      label: 'Img2Img',
      icon: React.createElement(Wand2),
      onClick: () => { setIsInpaintMode(true); setEditMode('img2img'); },
    },
    ...(isCloudMode && handleUpscale ? [{
      id: 'upscale',
      label: 'Enhance',
      icon: React.createElement(ArrowUp),
      onClick: () => { setIsInpaintMode(false); setEditMode('upscale'); },
    }] : []),
  ];

  const labelSize = isMobile ? 'text-[10px] uppercase tracking-wide text-muted-foreground' : 'text-sm';
  const textareaMinHeight = isMobile ? 'min-h-[50px]' : 'min-h-[100px]';
  const textareaRows = isMobile ? 2 : 4;
  const textareaPadding = isMobile ? 'px-2 py-1.5' : 'px-3 py-2';
  const textareaTextSize = isMobile ? 'text-base' : 'text-sm'; // 16px on mobile prevents iOS zoom
  const generationsSpacing = isMobile ? 'space-y-0.5' : 'space-y-2';

  return {
    isMobile,
    onClose,
    editMode,
    setEditMode,
    setIsInpaintMode,
    brushStrokes,
    handleExitMagicEditMode,
    hasTransformChanges,
    inpaintPrompt,
    setInpaintPrompt,
    inpaintNumGenerations,
    setInpaintNumGenerations,
    flushTextFields,
    loraMode,
    setLoraMode,
    customLoraUrl,
    setCustomLoraUrl,
    createAsGeneration,
    setCreateAsGeneration,
    img2imgPrompt,
    setImg2imgPrompt,
    img2imgStrength,
    setImg2imgStrength,
    setEnablePromptExpansion,
    qwenEditModel,
    setQwenEditModel,
    isGeneratingReposition,
    repositionGenerateSuccess,
    isSavingAsVariant,
    saveAsVariantSuccess,
    isGeneratingInpaint,
    inpaintGenerateSuccess,
    isCreatingMagicEditTasks,
    magicEditTasksCreated,
    isGeneratingImg2Img,
    img2imgGenerateSuccess,
    variants,
    activeVariantId,
    onVariantSelect,
    onMakePrimary,
    isLoadingVariants,
    onPromoteToGeneration,
    isPromoting,
    onDeleteVariant,
    onLoadVariantSettings,
    pendingTaskCount,
    unviewedVariantCount,
    onMarkAllViewed,
    onLoadVariantImages,
    currentSegmentImages,
    hasUserEditedPrompt,
    setHasUserEditedPrompt,
    handleClearLora,
    modeSelectorItems,
    labelSize,
    textareaMinHeight,
    textareaRows,
    textareaPadding,
    textareaTextSize,
    generationsSpacing,
  };
}

export type EditModePanelState = ReturnType<typeof useEditModePanelState>;

/**
 * ImageEditFormContext
 *
 * Form state for image editing: prompts, strengths, LoRA, model selection,
 * advanced settings, number of generations, variant toggle.
 *
 * Consumer: EditModePanel (only).
 * Split from ImageEditContext to avoid re-renders of canvas/overlay components
 * when the user is typing prompts or adjusting form controls.
 */

import React, { createContext, useContext } from 'react';
import type {
  LoraMode,
  QwenEditModel,
  EditAdvancedSettings,
} from '../model/editSettingsTypes';
import { DEFAULT_ADVANCED_SETTINGS } from '../model/editSettingsTypes';

export type { LoraMode };

// ============================================================================
// Types
// ============================================================================

export interface ImageEditFormState {
  inpaintPrompt: string;
  setInpaintPrompt: (value: string) => void;
  inpaintNumGenerations: number;
  setInpaintNumGenerations: (value: number) => void;
  flushTextFields: () => Promise<void>;
  img2imgPrompt: string;
  setImg2imgPrompt: (value: string) => void;
  img2imgStrength: number;
  setImg2imgStrength: (value: number) => void;
  enablePromptExpansion: boolean;
  setEnablePromptExpansion: (value: boolean) => void;
  loraMode: LoraMode;
  setLoraMode: (mode: LoraMode) => void;
  customLoraUrl: string;
  setCustomLoraUrl: (url: string) => void;
  createAsGeneration: boolean;
  setCreateAsGeneration: (value: boolean) => void;
  qwenEditModel: QwenEditModel;
  setQwenEditModel: (model: QwenEditModel) => void;
  advancedSettings: EditAdvancedSettings;
  setAdvancedSettings: (settings: EditAdvancedSettings) => void;
}

// ============================================================================
// Defaults
// ============================================================================

const EMPTY_FORM: ImageEditFormState = {
  inpaintPrompt: '',
  setInpaintPrompt: () => {},
  inpaintNumGenerations: 1,
  setInpaintNumGenerations: () => {},
  flushTextFields: async () => {},
  img2imgPrompt: '',
  setImg2imgPrompt: () => {},
  img2imgStrength: 0.6,
  setImg2imgStrength: () => {},
  enablePromptExpansion: false,
  setEnablePromptExpansion: () => {},
  loraMode: 'none',
  setLoraMode: () => {},
  customLoraUrl: '',
  setCustomLoraUrl: () => {},
  createAsGeneration: false,
  setCreateAsGeneration: () => {},
  qwenEditModel: 'qwen-edit-2511',
  setQwenEditModel: () => {},
  advancedSettings: DEFAULT_ADVANCED_SETTINGS,
  setAdvancedSettings: () => {},
};

// ============================================================================
// Context + Hook
// ============================================================================

const ImageEditFormContext = createContext<ImageEditFormState | null>(null);

interface ImageEditFormProviderProps {
  children: React.ReactNode;
  value: ImageEditFormState;
}

export const ImageEditFormProvider: React.FC<ImageEditFormProviderProps> = ({
  children,
  value,
}) => {
  return (
    <ImageEditFormContext.Provider value={value}>
      {children}
    </ImageEditFormContext.Provider>
  );
};

/**
 * Returns form edit state and fails loudly when the provider is missing.
 */
export function useImageEditForm(): ImageEditFormState {
  const context = useContext(ImageEditFormContext);
  if (!context) {
    throw new Error('useImageEditForm must be used within an ImageEditFormProvider');
  }
  return context;
}

/**
 * Returns form edit state, or safe defaults when missing a provider on purpose.
 */
export function useImageEditFormSafe(): ImageEditFormState {
  const context = useContext(ImageEditFormContext);
  return context ?? EMPTY_FORM;
}

