/**
 * ModeSelector Component
 *
 * A responsive mode selector that automatically switches to icon-only mode
 * when there isn't enough space to display text labels without truncation.
 */

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { cn } from '@/shared/components/ui/contracts/cn';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/shared/components/ui/tooltip';

interface ModeSelectorItem {
  id: string;
  label: string;
  icon: React.ReactNode;
  onClick: () => void;
}

interface ModeSelectorProps {
  items: ModeSelectorItem[];
  activeId: string;
  className?: string;
}

export const ModeSelector: React.FC<ModeSelectorProps> = ({
  items,
  activeId,
  className,
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const measureRef = useRef<HTMLDivElement>(null);
  const [showIconsOnly, setShowIconsOnly] = useState(false);

  // Calculate minimum width needed for text mode
  // Each button needs: icon (14px) + gap (6px) + text width + padding (24px horizontal)
  // Plus gaps between buttons
  const checkIfTextFits = useCallback(() => {
    const container = containerRef.current;
    const measureDiv = measureRef.current;
    if (!container || !measureDiv) return;

    // Get the available width (container width minus padding and gaps)
    const containerWidth = container.clientWidth;
    const padding = 8; // p-1 = 4px each side
    const gaps = (items.length - 1) * 4; // gap-1 = 4px between items
    const availableWidth = containerWidth - padding - gaps;

    // Measure the hidden text spans to get required width
    const spans = measureDiv.querySelectorAll('span');
    let totalRequiredWidth = 0;

    spans.forEach((span) => {
      // Each button needs: padding (24px) + icon (14px) + gap (6px) + text width
      const textWidth = span.scrollWidth;
      const buttonWidth = 24 + 14 + 6 + textWidth;
      totalRequiredWidth += buttonWidth;
    });

    // If we need more width than available, show icons only
    const needsIconsOnly = totalRequiredWidth > availableWidth;
    setShowIconsOnly(needsIconsOnly);
  }, [items]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // Initial check
    checkIfTextFits();

    // Set up ResizeObserver
    const resizeObserver = new ResizeObserver(() => {
      checkIfTextFits();
    });

    resizeObserver.observe(container);

    return () => {
      resizeObserver.disconnect();
    };
  }, [checkIfTextFits]);

  return (
    <>
      {/* Hidden measurement div - always renders text to measure */}
      <div
        ref={measureRef}
        className="absolute opacity-0 pointer-events-none whitespace-nowrap text-sm"
        aria-hidden="true"
      >
        {items.map((item) => (
          <span key={item.id} className="inline-block px-1">
            {item.label}
          </span>
        ))}
      </div>

      {/* Visible selector */}
      <div
        ref={containerRef}
        className={cn(
          "flex gap-1 border border-border rounded-lg overflow-hidden bg-muted/30 p-1",
          className
        )}
      >
        {items.map((item) => {
          const button = (
            <button
              key={item.id}
              onClick={(e) => {
                console.log('[ModeSelector] click', {
                  id: item.id,
                  activeId,
                  bodyPointerEvents: document.body.style.pointerEvents,
                  openOverlays: Array.from(document.querySelectorAll('[data-state="open"]')).map(
                    (el) => `${el.tagName}.${(el.getAttribute('class') ?? '').slice(0, 40)}`,
                  ),
                  activeElement: document.activeElement?.tagName,
                  defaultPrevented: e.defaultPrevented,
                });
                item.onClick();
              }}
              className={cn(
                "flex-1 min-w-0 flex items-center justify-center transition-all rounded overflow-hidden",
                showIconsOnly ? "p-2" : "gap-1.5 px-3 py-1.5 text-sm",
                activeId === item.id
                  ? "bg-background text-foreground font-medium shadow-sm"
                  : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
              )}
            >
              <span className={cn("flex-shrink-0", showIconsOnly ? "[&>svg]:h-4 [&>svg]:w-4" : "[&>svg]:h-3.5 [&>svg]:w-3.5")}>
                {item.icon}
              </span>
              {!showIconsOnly && (
                <span className="truncate">
                  {item.label}
                </span>
              )}
            </button>
          );

          // Wrap in tooltip when showing icons only
          if (showIconsOnly) {
            return (
              <Tooltip key={item.id}>
                <TooltipTrigger asChild>
                  {button}
                </TooltipTrigger>
                <TooltipContent side="bottom" className="text-xs">
                  {item.label}
                </TooltipContent>
              </Tooltip>
            );
          }

          return button;
        })}
      </div>
    </>
  );
};

import * as React from "react"
import { cn } from "@/shared/components/ui/contracts/cn"
import {
  TextFieldActionButtons,
  type ClearableVoiceFieldProps,
  useTextFieldActions,
} from "./textFieldActions"

export interface TextareaProps
  extends React.TextareaHTMLAttributes<HTMLTextAreaElement>,
    ClearableVoiceFieldProps {}

const Textarea = React.forwardRef<HTMLTextAreaElement, TextareaProps>(
  ({
    className,
    clearable = false,
    onClear,
    voiceInput = false,
    onVoiceResult,
    voiceTask = "transcribe_and_write",
    voiceContext,
    voiceExample,
    onVoiceError,
    ...props
  }, ref) => {
    const fieldActions = useTextFieldActions({
      value: props.value,
      defaultValue: props.defaultValue,
      clearable,
      onClear,
      voiceInput,
      onVoiceResult,
      disabled: props.disabled,
    })

    const isShortTextarea =
      className?.includes("h-8") || className?.includes("min-h-0") || className?.includes("h-10")

    return (
      <div
        className="relative"
        onMouseEnter={() => fieldActions.setIsHovered(true)}
        onMouseLeave={() => fieldActions.setIsHovered(false)}
      >
        <textarea
          className={cn(
            "flex min-h-[80px] w-full rounded-md border border-input bg-background px-3 py-2 text-base lg:text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50 preserve-case",
            fieldActions.hasActions && "pr-10",
            className
          )}
          ref={ref}
          {...props}
        />

        {fieldActions.showButtons && (
          <TextFieldActionButtons
            showVoice={fieldActions.showVoice}
            showClear={fieldActions.showClear}
            existingValue={fieldActions.existingValue}
            disabled={props.disabled}
            onVoiceActiveStateChange={fieldActions.setIsAIInputActive}
            onClearClick={fieldActions.handleClear}
            containerClassName={cn(
              "absolute right-0 z-10",
              isShortTextarea
                ? "top-1/2 -translate-y-1/2 right-2 flex items-center gap-1"
                : "top-0 bottom-0 w-8 flex flex-col items-center gap-1 py-1.5"
            )}
            voiceButtonClassName={isShortTextarea ? undefined : "flex-1 w-6 min-h-0"}
            clearButtonClassName="flex-shrink-0"
            voiceTask={voiceTask}
            onVoiceResult={onVoiceResult}
            onVoiceError={onVoiceError}
            voiceContext={voiceContext}
            voiceExample={voiceExample}
          />
        )}
      </div>
    )
  }
)
Textarea.displayName = "Textarea"

