import React, { useRef } from 'react';
import { cn } from '@/shared/components/ui/contracts/cn';
import { SegmentedControl, SegmentedControlItem } from '@/shared/components/ui/segmented-control';
import { VariantSelector } from '@/shared/components/VariantSelector';
import type { GenerationVariant } from '@/shared/hooks/variants/useVariants';
import { useCopyToClipboard } from '@/shared/hooks/clipboard/useCopyToClipboard';
import { PanelCloseButton, PanelHeaderMeta } from './PanelHeaderControls';
import type { CurrentSegmentImagesData } from '@/shared/components/VariantSelector/variantSourceImages';

const NOOP = () => {};

interface EditPanelLayoutProps {
  /** Layout variant */
  variant: 'desktop' | 'mobile';

  /** Handler to close the lightbox */
  onClose: () => void;

  /** Handler to exit edit mode (switch to info view) */
  onExitEditMode: () => void;

  /** Whether to hide the Info/Edit toggle */
  hideInfoEditToggle?: boolean;

  /**
   * Simplified header mode for page views (edit-images, edit-video tools).
   * When true, shows only [ModeSelector | X button] in header.
   * When false (default), shows full header with id copy, variants link, pending badge, etc.
   */
  simplifiedHeader?: boolean;

  /** Mode selector content (the toggle buttons) */
  modeSelector: React.ReactNode;

  /** Main content below the mode selector */
  children: React.ReactNode;

  /** Task ID for copy functionality */
  taskId?: string | null;

  /** Variants props */
  variants?: GenerationVariant[];
  activeVariantId?: string | null;
  onVariantSelect?: (variantId: string) => void;
  onMakePrimary?: (variantId: string) => Promise<void>;
  isLoadingVariants?: boolean;

  /** Variant promotion (only for images) */
  onPromoteToGeneration?: (variantId: string) => Promise<void>;
  isPromoting?: boolean;

  pendingTaskCount?: number;
  unviewedVariantCount?: number;
  onMarkAllViewed?: () => void;

  /** Handler to load a variant's settings into the regenerate form */
  onLoadVariantSettings?: (variantParams: Record<string, unknown>) => void;
  onLoadVariantImages?: (variant: GenerationVariant) => void;
  currentSegmentImages?: CurrentSegmentImagesData;

  /** Handler to delete a variant */
  onDeleteVariant?: (variantId: string) => Promise<void>;

}

export const EditPanelLayout: React.FC<EditPanelLayoutProps> = ({
  variant,
  onClose,
  onExitEditMode,
  hideInfoEditToggle = false,
  simplifiedHeader = false,
  modeSelector,
  children,
  taskId,
  variants,
  activeVariantId,
  onVariantSelect,
  onMakePrimary,
  isLoadingVariants,
  onPromoteToGeneration,
  isPromoting,
  pendingTaskCount = 0,
  unviewedVariantCount = 0,
  onMarkAllViewed = NOOP,
  onLoadVariantSettings,
  onLoadVariantImages,
  currentSegmentImages,
  onDeleteVariant,
}) => {
  const isMobile = variant === 'mobile';
  const hasVariants = variants && variants.length >= 1 && onVariantSelect;
  const padding = isMobile ? 'p-3' : 'p-6';
  const spacing = isMobile ? 'space-y-2' : 'space-y-4';
  const { copied: idCopied, handleCopy: handleCopyId } = useCopyToClipboard(taskId ?? undefined);
  const variantsSectionRef = useRef<HTMLDivElement>(null);

  return (
    <div className="h-full flex flex-col">
      {/* Header - simplified or full based on prop */}
      {simplifiedHeader ? (
        /* Simplified header for page views: just [ModeSelector | X] */
        <div className={cn(
          "flex items-center justify-between border-b border-border bg-background flex-shrink-0",
          isMobile ? "px-3 py-2 gap-2" : "p-4 gap-3"
        )}>
          {/* Mode selector takes available space */}
          <div className="flex-1">
            {modeSelector}
          </div>

          {/* Close button */}
          <PanelCloseButton
            isMobile={isMobile}
            onClose={onClose}
            stopPropagation
            className="flex-shrink-0"
          />
        </div>
      ) : (
        /* Full header for MediaLightbox: ID copy, variants link, pending badge, Info/Edit toggle, close */
        <div className={cn(
          "flex items-center justify-between border-b border-border bg-background flex-shrink-0",
          isMobile ? "px-3 py-2 gap-2" : "p-4 gap-3"
        )}>
          <PanelHeaderMeta
            taskId={taskId}
            idCopied={idCopied}
            onCopyId={handleCopyId}
            hasVariants={Boolean(hasVariants)}
            variants={variants ?? []}
            pendingTaskCount={pendingTaskCount}
            unviewedVariantCount={unviewedVariantCount}
            onMarkAllViewed={onMarkAllViewed}
            variantsSectionRef={variantsSectionRef}
          />

          {/* Right side - toggles and close button */}
          <div className="flex items-center gap-3">
            {!hideInfoEditToggle && (
              <SegmentedControl
                value="edit"
                onValueChange={(value) => {
                  if (value === 'info') {
                    onExitEditMode();
                  }
                }}
              >
                <SegmentedControlItem value="info">Info</SegmentedControlItem>
                <SegmentedControlItem value="edit">Edit</SegmentedControlItem>
              </SegmentedControl>
            )}
            <PanelCloseButton
              isMobile={isMobile}
              onClose={onClose}
              stopPropagation
            />
          </div>
        </div>
      )}

      {/* Scrollable content area */}
      <div className="flex-1 overflow-y-auto min-h-0 overscroll-none">
        {/* Mode selector section - only shown when NOT using simplified header */}
        {!simplifiedHeader && (
          <div className={cn("border-b border-border", isMobile ? "p-2" : "px-6 py-3")}>
            {modeSelector}
          </div>
        )}

        {/* Main content */}
        <div className={cn(padding, spacing)}>
          {children}
        </div>

        {/* Variants section - inside scroll area */}
        {hasVariants && (
          <div
            ref={variantsSectionRef}
            className={cn("border-t border-border", isMobile ? "pt-2 mt-2 px-3 pb-2" : "pt-4 mt-4 p-4")}
          >
            <VariantSelector
              variants={variants}
              activeVariantId={activeVariantId || null}
              onVariantSelect={onVariantSelect}
              onMakePrimary={onMakePrimary}
              isLoading={isLoadingVariants}
              onPromoteToGeneration={onPromoteToGeneration}
              isPromoting={isPromoting}
              onLoadVariantSettings={onLoadVariantSettings}
              onLoadVariantImages={onLoadVariantImages}
              currentSegmentImages={currentSegmentImages}
              onDeleteVariant={onDeleteVariant}
            />
          </div>
        )}
      </div>
    </div>
  );
};

import { useEffect, useRef } from 'react';

type MountTelemetry = {
  budget: number;
  count: number;
  name: string;
};

export type RenderBudgetTelemetryEntry = {
  budget: number;
  maxCount: number;
  mounts: number;
  name: string;
  status: 'over' | 'under';
};

type TelemetryListener = () => void;

const INTERACTION_WINDOW_MS = 1000;

const mountTelemetry = new Map<number, MountTelemetry>();
const listeners = new Set<TelemetryListener>();

let nextInstanceId = 1;

export function isRenderBudgetRuntimeEnabled(): boolean {
  const forceEnabled = (globalThis as { __REIGH_FORCE_RENDER_TELEMETRY__?: boolean }).__REIGH_FORCE_RENDER_TELEMETRY__ === true;
  if (Boolean(import.meta.env.VITEST) || import.meta.env.MODE === 'test') {
    return forceEnabled;
  }

  return import.meta.env.DEV || import.meta.env.MODE === 'development';
}

function emitTelemetryChange() {
  for (const listener of listeners) {
    listener();
  }
}

function upsertMountTelemetry(instanceId: number, telemetry: MountTelemetry) {
  mountTelemetry.set(instanceId, telemetry);
  emitTelemetryChange();
}

function removeMountTelemetry(instanceId: number) {
  if (mountTelemetry.delete(instanceId)) {
    emitTelemetryChange();
  }
}

export function getRenderBudgetTelemetrySnapshot(): RenderBudgetTelemetryEntry[] {
  const grouped = new Map<string, RenderBudgetTelemetryEntry>();

  for (const telemetry of mountTelemetry.values()) {
    const current = grouped.get(telemetry.name);
    if (current === undefined) {
      grouped.set(telemetry.name, {
        budget: telemetry.budget,
        maxCount: telemetry.count,
        mounts: 1,
        name: telemetry.name,
        status: telemetry.count > telemetry.budget ? 'over' : 'under',
      });
      continue;
    }

    const maxCount = Math.max(current.maxCount, telemetry.count);
    const budget = Math.max(current.budget, telemetry.budget);
    grouped.set(telemetry.name, {
      ...current,
      budget,
      maxCount,
      mounts: current.mounts + 1,
      status: maxCount > budget ? 'over' : 'under',
    });
  }

  return Array.from(grouped.values()).sort((a, b) => a.name.localeCompare(b.name));
}

export function subscribeRenderBudgetTelemetry(listener: TelemetryListener): () => void {
  listeners.add(listener);
  return () => {
    listeners.delete(listener);
  };
}

export function resetRenderBudgetTelemetryForTests(): void {
  mountTelemetry.clear();
  listeners.clear();
  nextInstanceId = 1;
}

export function useRenderBudget(name: string, budget: number): void {
  const instanceIdRef = useRef<number | null>(null);
  const countRef = useRef(0);
  const idleTimerRef = useRef<number | null>(null);
  const lastRenderAtRef = useRef<number>(0);
  const warnedInWindowRef = useRef(false);

  if (instanceIdRef.current === null) {
    instanceIdRef.current = nextInstanceId++;
  }

  const isDev = isRenderBudgetRuntimeEnabled();

  if (isDev) {
    const now = Date.now();
    if (lastRenderAtRef.current > 0 && now - lastRenderAtRef.current > INTERACTION_WINDOW_MS) {
      countRef.current = 0;
      warnedInWindowRef.current = false;
    }

    countRef.current += 1;
    lastRenderAtRef.current = now;

    if (countRef.current > budget && !warnedInWindowRef.current) {
      console.warn(`[RenderBudget] ${name} rendered ${countRef.current} times (budget ${budget})`);
      warnedInWindowRef.current = true;
    }
  }

  useEffect(() => {
    if (!isDev) {
      return;
    }

    const instanceId = instanceIdRef.current!;

    upsertMountTelemetry(instanceId, {
      budget,
      count: countRef.current,
      name,
    });

    if (idleTimerRef.current !== null) {
      window.clearTimeout(idleTimerRef.current);
    }

    idleTimerRef.current = window.setTimeout(() => {
      countRef.current = 0;
      warnedInWindowRef.current = false;
      lastRenderAtRef.current = 0;

      upsertMountTelemetry(instanceId, {
        budget,
        count: 0,
        name,
      });
    }, INTERACTION_WINDOW_MS);
  });

  useEffect(() => {
    if (!isDev) {
      return;
    }

    const instanceId = instanceIdRef.current!;

    return () => {
      if (idleTimerRef.current !== null) {
        window.clearTimeout(idleTimerRef.current);
      }
      removeMountTelemetry(instanceId);
    };
  }, [isDev]);
}

